class Solution {
public:
    int maximumLength(string s) {
        int n = s.size();
        int max_len = 0;
        for (int i = 0; i < n; i++) {
            unordered_map<char, int> freq;
            for (int j = i; j < n; j++) {
                freq[s[j]]++;
                if (freq.size() == 1 && freq[s[j]] >= 3) {
                    max_len = max(max_len, j - i + 1);
                }
            }
        }
        return max_len > 0 ? max_len : -1;
    }
};
```

